CustomFunction.Calculation:
// Rebuilds outerQuery's bindings array as [prefixBindings...][suffixBindings...].
// prefixBindings is a subquery's bindings JSON array (written first because
// the subquery appears in FROM, before WHERE in SQL). suffixBindings is the
// outer query's existing bindings JSON array. Call with index = 0.
// On the final iteration writes the new bindingCount = prefixCount + suffixCount.
// Used by QueryFromSubquery to ensure correct ? placeholder order.
Let
(
[
_total = prefixCount + suffixCount ;
_value = If ( index < prefixCount ;
	JSONGetElement ( prefixBindings ; "[" & index & "]" ) ;
	JSONGetElement ( suffixBindings ; "[" & ( index - prefixCount ) & "]" )
	) ;
_q1 = JSONSetElement ( outerQuery ; "bindings[" & index & "]" ; _value ; JSONString )
];
If ( index + 1 < _total ;
	QueryPrependBindings ( _q1 ; prefixBindings ; prefixCount ; suffixBindings ; suffixCount ; index + 1 ) ;
// ELSE last element: write final bindingCount
	JSONSetElement ( _q1 ; "bindingCount" ; _total ; JSONNumber )
)
)
